import{_ as i,c as a,o,ak as s,ap as t}from"./chunks/framework.DHLlVITf.js";const u=JSON.parse('{"title":"AireForms Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireforms-v11-3-1.md","filePath":"aireblock-releases/aireforms-v11-3-1.md","lastUpdated":1784558859000}'),r={name:"aireblock-releases/aireforms-v11-3-1.md"};function l(n,e,c,d,m,p){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="aireforms-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+t+'"> AireForms Release Notes</span> <a class="header-anchor" href="#aireforms-release-notes" aria-label="Permalink to “AireForms Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 11.3.1<br><strong>Release Date:</strong> 15 July 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Collapsible Building Block Panels (AFORMS-4072)</li><li>Adds some of the groundwork for AireTheme support. However, it will be disabled and enabled at a future date</li><li>Smarter Form Type Selection in the Form Builder (AFORMS-4098)</li><li>Improved Visibility into Server-Side Calculations (AFORMS-4106)</li><li>Improved Dropdown Selects in the Form Builder (AFORMS-4107)</li><li>More Reliable Single Pass Form Submissions (AFORMS-4122)</li><li>Safer Form Version Upgrades (AFORMS-4125)</li><li>New Barcode Scanner Control (AFORMS-4134)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Clearer Import Failure Notifications (AFORMS-4111)</li><li>Fixed Preview Tab Opening on Failed Import (AFORMS-4112)</li><li>Fixed Building Block Import with Formatted Text Validation (AFORMS-4113)</li><li>Fixed Forms Getting Stuck When They Fail to Load (AFORMS-4117)</li><li>Fixed PDF Highlighting for Select Controls in Repeats (AFORMS-4123)</li><li>Fixed PDF Generation Failure with Hidden Repeatable Grid Fields (AFORMS-4124)</li><li>Fixed Lazy Multi-Select Buttons in Read View (AFORMS-4141)</li></ul><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="collapsible-building-block-panels-aforms-4072" tabindex="-1">Collapsible Building Block Panels (AFORMS-4072) <a class="header-anchor" href="#collapsible-building-block-panels-aforms-4072" aria-label="Permalink to “Collapsible Building Block Panels (AFORMS-4072)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>On long forms it was difficult to locate the building block you needed. Each block in the form builder now appears in a collapsible panel, showing the block name and last updated details in the header, with all panels collapsed by default.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now scan long forms much more quickly in the dev tools, expanding only the blocks you actually need to work on instead of scrolling through everything.</p></div><h4 id="clinician-forms-now-support-tenant-theming-aforms-4076-disabled" tabindex="-1">Clinician Forms Now Support Tenant Theming (AFORMS-4076) - (Disabled) <a class="header-anchor" href="#clinician-forms-now-support-tenant-theming-aforms-4076-disabled" aria-label="Permalink to “Clinician Forms Now Support Tenant Theming (AFORMS-4076) - (Disabled)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Clinician forms now integrate with AireTheme via gRPC, allowing custom highlighting of explanatory text controls to match your organisation&#39;s configured theme. If no theme is configured, forms fall back to the default (orgs.xml) styling.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your clinician forms will automatically pick up your organisation&#39;s branding and colours, giving your users a more consistent experience.</p></div><h4 id="single-pass-forms-now-support-tenant-theme-colours-aforms-4077-disabled" tabindex="-1">Single Pass Forms Now Support Tenant Theme Colours (AFORMS-4077) - (Disabled) <a class="header-anchor" href="#single-pass-forms-now-support-tenant-theme-colours-aforms-4077-disabled" aria-label="Permalink to “Single Pass Forms Now Support Tenant Theme Colours (AFORMS-4077) - (Disabled)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Single pass forms now integrate with AireTheme via gRPC, applying custom highlighting to explanatory text controls and respecting the configured theme for buttons, text, and other elements.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Single pass forms will look and feel consistent with the rest of your branded experience, without any extra work on your part.</p></div><h4 id="single-pass-forms-now-display-your-tenant-logo-aforms-4080-disabled" tabindex="-1">Single Pass Forms Now Display Your Tenant Logo (AFORMS-4080) - (Disabled) <a class="header-anchor" href="#single-pass-forms-now-display-your-tenant-logo-aforms-4080-disabled" aria-label="Permalink to “Single Pass Forms Now Display Your Tenant Logo (AFORMS-4080) - (Disabled)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Single pass forms can now display the logo configured in AireTheme. Where no theme is configured for a tenant, forms fall back to the previous approach using orgs.xml.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Your logo will now appear on single pass forms automatically, reinforcing your brand at every step.</p></div><h4 id="smarter-form-type-selection-in-the-form-builder-aforms-4098" tabindex="-1">Smarter Form Type Selection in the Form Builder (AFORMS-4098) <a class="header-anchor" href="#smarter-form-type-selection-in-the-form-builder-aforms-4098" aria-label="Permalink to “Smarter Form Type Selection in the Form Builder (AFORMS-4098)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The form builder no longer defaults to a specific form type when creating a new form, reducing accidental creation of single pass forms when a clinician form was intended.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;re less likely to accidentally create the wrong type of form, saving you the hassle of withdrawing and recreating it under a new key.</p></div><h4 id="improved-visibility-into-server-side-calculations-aforms-4106" tabindex="-1">Improved Visibility into Server-Side Calculations (AFORMS-4106) <a class="header-anchor" href="#improved-visibility-into-server-side-calculations-aforms-4106" aria-label="Permalink to “Improved Visibility into Server-Side Calculations (AFORMS-4106)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Telemetry has been added for external server-side calculations, logging the tenant, key, and version used. Calculation parameters are not logged.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Support and engineering teams can now diagnose calculation issues more easily, helping problems get resolved faster.</p></div><h4 id="improved-dropdown-selects-in-the-form-builder-aforms-4107" tabindex="-1">Improved Dropdown Selects in the Form Builder (AFORMS-4107) <a class="header-anchor" href="#improved-dropdown-selects-in-the-form-builder-aforms-4107" aria-label="Permalink to “Improved Dropdown Selects in the Form Builder (AFORMS-4107)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Form builder select controls have been updated to use non-native (Mui) selects, resolving a display issue that occurred when a select contained an adornment.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Dropdowns in the form builder now display correctly and consistently, with no visual glitches when extra icons or adornments are present.</p></div><h4 id="more-reliable-single-pass-form-submissions-aforms-4122" tabindex="-1">More Reliable Single Pass Form Submissions (AFORMS-4122) <a class="header-anchor" href="#more-reliable-single-pass-form-submissions-aforms-4122" aria-label="Permalink to “More Reliable Single Pass Form Submissions (AFORMS-4122)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Single pass form persistence has been made more idempotent by storing a transaction ID against a composite form and checking for existing submissions before storing new data, based on tenant, subject, and transaction ID.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can be more confident that a single form submission won&#39;t accidentally be recorded twice.</p></div><h4 id="safer-form-version-upgrades-aforms-4125" tabindex="-1">Safer Form Version Upgrades (AFORMS-4125) <a class="header-anchor" href="#safer-form-version-upgrades-aforms-4125" aria-label="Permalink to “Safer Form Version Upgrades (AFORMS-4125)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The Form Designer now forces a version upgrade for production clinician forms when building blocks have changed version or been removed, under configurations that include save draft, allow amends, or pre-population. Users are notified before a new version is created.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You&#39;ll be warned before changes could affect forms already in production, helping prevent the kind of incidents this update was designed to avoid.</p></div><h4 id="new-barcode-scanner-control-aforms-4134" tabindex="-1">New Barcode Scanner Control (AFORMS-4134) <a class="header-anchor" href="#new-barcode-scanner-control-aforms-4134" aria-label="Permalink to “New Barcode Scanner Control (AFORMS-4134)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A barcode scanner control has been enabled in the form designer.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now add barcode scanning directly to your forms, making it easier to capture data quickly and accurately.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="clearer-import-failure-notifications-aforms-4111" tabindex="-1">Clearer Import Failure Notifications (AFORMS-4111) <a class="header-anchor" href="#clearer-import-failure-notifications-aforms-4111" aria-label="Permalink to “Clearer Import Failure Notifications (AFORMS-4111)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Importing or previewing a building block that resulted in a 500 error did not display an import failed notification. This has been fixed so the failure is now shown to the user.</p></div><h4 id="fixed-preview-tab-opening-on-failed-import-aforms-4112" tabindex="-1">Fixed Preview Tab Opening on Failed Import (AFORMS-4112) <a class="header-anchor" href="#fixed-preview-tab-opening-on-failed-import-aforms-4112" aria-label="Permalink to “Fixed Preview Tab Opening on Failed Import (AFORMS-4112)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Previewing a form in the building block designer that resulted in a 500 error would open the preview tab showing the last successfully previewed block. The preview tab no longer opens when the import fails.</p></div><h4 id="fixed-building-block-import-with-formatted-text-validation-aforms-4113" tabindex="-1">Fixed Building Block Import with Formatted Text Validation (AFORMS-4113) <a class="header-anchor" href="#fixed-building-block-import-with-formatted-text-validation-aforms-4113" aria-label="Permalink to “Fixed Building Block Import with Formatted Text Validation (AFORMS-4113)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Importing a building block containing a formatted text area with multiple custom validation messages failed during the XSLT transformation step. This issue has been resolved.</p></div><h4 id="fixed-forms-getting-stuck-when-they-fail-to-load-aforms-4117" tabindex="-1">Fixed Forms Getting Stuck When They Fail to Load (AFORMS-4117) <a class="header-anchor" href="#fixed-forms-getting-stuck-when-they-fail-to-load-aforms-4117" aria-label="Permalink to “Fixed Forms Getting Stuck When They Fail to Load (AFORMS-4117)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>When a form failed to load, sending the close-form message had no effect, which could leave users trapped in the outer system. This has been corrected so the close-form message works correctly even when the form fails to load.</p></div><h4 id="fixed-pdf-highlighting-for-select-controls-in-repeats-aforms-4123" tabindex="-1">Fixed PDF Highlighting for Select Controls in Repeats (AFORMS-4123) <a class="header-anchor" href="#fixed-pdf-highlighting-for-select-controls-in-repeats-aforms-4123" aria-label="Permalink to “Fixed PDF Highlighting for Select Controls in Repeats (AFORMS-4123)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Selecting a highlight option in the PDF for a select control inside a repeat caused an XSLT error. This has been fixed.</p></div><h4 id="fixed-pdf-generation-failure-with-hidden-repeatable-grid-fields-aforms-4124" tabindex="-1">Fixed PDF Generation Failure with Hidden Repeatable Grid Fields (AFORMS-4124) <a class="header-anchor" href="#fixed-pdf-generation-failure-with-hidden-repeatable-grid-fields-aforms-4124" aria-label="Permalink to “Fixed PDF Generation Failure with Hidden Repeatable Grid Fields (AFORMS-4124)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Choosing &quot;Hide from PDF&quot; on a control within a repeatable grid caused the PDF generator to fail, making the PDF unviewable. This has been resolved.</p></div><h4 id="fixed-lazy-multi-select-buttons-in-read-view-aforms-4141" tabindex="-1">Fixed Lazy Multi-Select Buttons in Read View (AFORMS-4141) <a class="header-anchor" href="#fixed-lazy-multi-select-buttons-in-read-view-aforms-4141" aria-label="Permalink to “Fixed Lazy Multi-Select Buttons in Read View (AFORMS-4141)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The lazy multi-select buttons control was not supported in the read view, causing an error. This control is now supported in read view.</p></div>',56)])])}const f=i(r,[["render",l]]);export{u as __pageData,f as default};
